scwin.f_validate = async function () {
    let chk = await $c.gus.cfValidate([ed_hhetd, ed_hhondt, ed_hheta, ed_hhisudt, ed_creadyDt, ed_hhcurdt, ed_mhcurdt]);
    if (!chk) return false;
    let chk1 = await $c.gus.cfValidate([gr_selling, gr_buying]);
    if (!chk1) return false;

    if ($c.util.isEmpty(ed_hhcur.getValue())) {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Currency"]);
        ed_hhcur.focus();
        return false;
    }
    if ($c.util.isEmpty(ed_mhcur.getValue())) {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Currency"]);
        ed_mhcur.focus();
        return false;
    }
    if ($c.util.isEmpty(ed_hhbkgno.getValue())) {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Booking No"]);
        ed_hhbkgno.focus();
        return false;
    }

    if ($c.util.isEmpty(lc_hhbkgseq.getValue())) {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Seq"]); //@는 필수입력항목입니다.

        tbc_main.setSelectedTabIndex(0);
        ed_hhbkgno.focus();
        return false;
    }

    if ($c.util.isEmpty(ed_hhetd.getValue())) {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["ETD"]);
        ed_hhetd.focus();
        return false;
    }
    if ($c.util.isEmpty(ed_creadyDt.getValue())) {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Result Date"]);
        tbc_main.setSelectedTabIndex(0);
        ed_creadyDt.focus();
        return false;
    }

    if (!$c.util.isEmpty(ed_hheta.getValue())) {
        if (!$c.gus.cfIsAfterDate(ed_hhetd.getValue(), ed_hheta.getValue())) {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_048, ["ETD", "ETA"]);
            tbc_main.setSelectedTabIndex(0);
            ed_hhetd.focus();
            return false;
        }
    }

    if ($c.gus.cfMonthsBetween(scwin.strCurDate.toDate(), ed_hhetd.getValue().toDate()) > 3) {
        await $c.gus.cfAlertMsg("ETD가 저장하는 날짜로 부터 3개월 이상의 미래일 수 없습니다.");
        tbc_main.setSelectedTabIndex(0);
        ed_hhetd.focus();
        return false;
    }

    if (!$c.util.isEmpty(ed_hheta.getValue()) && $c.gus.cfMonthsBetween(scwin.strCurDate.toDate(), ed_hheta.getValue().toDate()) > 3) {
        await $c.gus.cfAlertMsg("ETA가 저장하는 날짜로 부터 3개월 이상의 미래일 수 없습니다.");
        tbc_main.setSelectedTabIndex(0);
        ed_hheta.focus();
        return false;
    }
    if ($c.gus.cfYearsBetween(ed_hhetd.getValue().toDate(), scwin.strCurDate.toDate()) > 3) {
        await $c.gus.cfAlertMsg("ETD가 3년 이상의 과거 일 수 없습니다.");
        tbc_main.setSelectedTabIndex(0);
        ed_hhetd.focus();
        return false;
    }
    if (!$c.util.isEmpty(ed_hheta.getValue()) && $c.gus.cfYearsBetween(ed_hheta.getValue().toDate(), scwin.strCurDate.toDate()) > 3) {
        await $c.gus.cfAlertMsg("ETA가 3년 이상의 과거 일 수 없습니다.");
        tbc_main.setSelectedTabIndex(0);
        ed_hheta.focus();
        return false;
    }
    if (!$c.util.isEmpty(ed_hheta.getValue()) && $c.date.diffDate(ed_hhetd.getValue(), ed_hheta.getValue()) > 149) {
        await $c.gus.cfAlertMsg("ETA-ETD(transit time)가 150일을 초과할 수 없습니다.");
        tbc_main.setSelectedTabIndex(0);
        ed_hhetd.focus(); return false;
    }
    if ($c.util.isEmpty(ed_hhactcust.getValue()) || ed_hhactcust.getValue() == "999908") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Customer"]);
        tbc_main.setSelectedTabIndex(0);
        ed_hhactcust.focus();
        return false;
    }
    if ($c.util.isEmpty(ed_hhbuyer.getValue())) {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Department"]);
        tbc_main.setSelectedTabIndex(0);
        ed_hhbuyer.focus();
        return false;
    }
    if ($c.util.isEmpty(ed_hhitem.getValue())) {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Item"]);
        tbc_main.setSelectedTabIndex(1);
        ed_hhitem.focus();
        return false;
    }
    if ($c.util.isEmpty(txt_hhmitem1.getValue())) {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Item Name"]);
        tbc_main.setSelectedTabIndex(1);
        txt_hhmitem1.focus();
        return false;
    }
    if (scwin.statusFlag == "C") {
        if (cnd_ed_hhblno.getValue().length != 2 && cnd_ed_hhblno.getValue().substring(0, 2) == "DE") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_026, ["Auto Create", "DE"]);
            cnd_ed_hhblno.focus();
            return false;
        }
    }
    if (!(await scwin.f_containerDualCheck())) {
        return false;
    }

    if (!$c.util.isEmpty(ed_hhcnt1type.getValue())) {
        var nRow = ds_containerType.getMatchedIndex("code", ed_hhcnt1type.getValue());
        if (nRow == -1) {  // 값이 없을때
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ["Container Type"]); //  @이(가) 존재하지 않습니다.
            tbc_main.setSelectedTabIndex(0);  // 1번째 탭으로 이동.  cnd_ed_hhblno.focus() 잡아주기 위함.			     
            ed_hhcnt1type.focus();
            return false;
        }
    }

    // Container Type value check	
    if (!$c.util.isEmpty(ed_hhcnt2type.getValue())) {
        var nRow = ds_containerType.getMatchedIndex("code", ed_hhcnt2type.getValue());
        if (nRow == -1) {  // 값이 없을때
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ["Container Type"]); //  @이(가) 존재하지 않습니다.
            tbc_main.setSelectedTabIndex(0);  // 1번째 탭으로 이동.  cnd_ed_hhblno.focus() 잡아주기 위함.			     
            ed_hhcnt2type.focus();
            return false;
        }
    }

    // Container Type value check	
    if (!$c.util.isEmpty(ed_hhcnt3type.getValue())) {
        var nRow = ds_containerType.getMatchedIndex("code", ed_hhcnt3type.getValue());
        if (nRow == -1) {  // 값이 없을때
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ["Container Type"]); //  @이(가) 존재하지 않습니다.
            tbc_main.setSelectedTabIndex(0);  // 1번째 탭으로 이동.  cnd_ed_hhblno.focus() 잡아주기 위함.			     		     
            ed_hhcnt3type.focus();
            return false;
        }
    }

    // Container Type value check	
    if (!$c.util.isEmpty(ed_hhcnt4type.getValue())) {
        var nRow = ds_containerType.getMatchedIndex("code", ed_hhcnt4type.getValue());
        if (nRow == -1) {  // 값이 없을때
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ["Container Type"]); //  @이(가) 존재하지 않습니다.
            tbc_main.setSelectedTabIndex(0);  // 1번째 탭으로 이동.  cnd_ed_hhblno.focus() 잡아주기 위함.			     		     
            ed_hhcnt4type.focus();
            return false;
        }
    }

    for (let i = 0; i < ds_ocContList.getRowCount(); i++) {
        if ($c.util.isEmpty(ds_ocContList.getCellData(i, "mccntno"))) {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Container"]);
            gr_ocContList.setFocusedCell(i, "mccntno", true);
            return false;
        }
    }
    for (let i = 0; i < ds_ocDirectMblno.getRowCount(); i++) {
        if ($c.util.isEmpty(ds_ocDirectMblno.getCellData(i, "oblno"))) {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Master B/L"]);
            gr_ocDirectMblno.setFocusedCell(i, "oblno", true);
            return false;
        }
    }

    for (let i = 0; i < ds_selling.getRowCount(); i++) {
        if ($c.util.isEmpty(ds_selling.getCellData(i, "bilgClntNo"))) {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Customer"]);
            gr_selling.setFocusedCell(i, "bilgClntNo", true);
            return false;
        }
        if ($c.util.isEmpty(ds_selling.getCellData(i, "bilgClntNm"))) {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Customer Name"]);
            gr_selling.setFocusedCell(i, "bilgClntNm", true);
            return false;
        }
        if ($c.util.isEmpty(ds_selling.getCellData(i, "fareEngCd"))) {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["F/Code"]);
            gr_selling.setFocusedCell(i, "fareEngCd", true);
            return false;
        }
        if ($c.util.isEmpty(ds_selling.getCellData(i, "crcCd"))) {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Currency"]);
            gr_selling.setFocusedCell(i, "crcCd", true);
            return false;
        }
        if ($c.util.isEmpty(ds_selling.getCellData(i, "fareUnit"))) {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Unit"]);
            gr_selling.setFocusedCell(i, "fareUnit", true);
            return false;
        }
    }
    for (let i = 0; i < ds_buying.getRowCount(); i++) {
        if ($c.util.isEmpty(ds_buying.getCellData(i, "pchsTyp"))) {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Type"]);
            gr_buying.setFocusedCell(i, "pchsTyp", true);
            return false;
        }
        if ($c.util.isEmpty(ds_buying.getCellData(i, "pchsClntNo"))) {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Customer"]);
            gr_buying.setFocusedCell(i, "pchsClntNo", true);
            return false;
        }
        if ($c.util.isEmpty(ds_buying.getCellData(i, "pchsClntNm"))) {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Customer Name"]);
            gr_buying.setFocusedCell(i, "pchsClntNm", true);
            return false;
        }
        if ($c.util.isEmpty(ds_buying.getCellData(i, "fareEngCd"))) {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["F/Code"]);
            gr_buying.setFocusedCell(i, "fareEngCd", true);
            return false;
        }
        if ($c.util.isEmpty(ds_buying.getCellData(i, "crcCd"))) {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Currency"]);
            gr_buying.setFocusedCell(i, "crcCd", true);
            return false;
        }
        if ($c.util.isEmpty(ds_buying.getCellData(i, "fareUnit"))) {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Unit"]);
            gr_buying.setFocusedCell(i, "fareUnit", true);
            return false;
        }
        if (ds_buying.getCellData(i, "pchsTyp") == "3" && $c.util.isEmpty(ds_buying.getCellData(i, "sellDeptCd"))) {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Inner Department"]);
            gr_buying.setFocusedCell(i, "sellDeptCd", true);
            return false;
        }
    }
    if (!(await scwin.f_JobCloseYn())) {  // 확인필요
        return false;
    }
    return true;
};

scwin.f_containerDualCheck = async function () {
    let v = "0";
    let t1 = ed_hhcnt1type.getValue(), t2 = ed_hhcnt2type.getValue(), t3 = ed_hhcnt3type.getValue(), t4 = ed_hhcnt4type.getValue();
    if (!$c.util.isEmpty(t1) && !$c.util.isEmpty(t2) && t1 == t2) v = "1";
    if (!$c.util.isEmpty(t1) && !$c.util.isEmpty(t3) && t1 == t3) v = "1";
    if (!$c.util.isEmpty(t1) && !$c.util.isEmpty(t4) && t1 == t4) v = "1";
    if (!$c.util.isEmpty(t2) && !$c.util.isEmpty(t3) && t2 == t3) v = "1";
    if (!$c.util.isEmpty(t2) && !$c.util.isEmpty(t4) && t2 == t4) v = "1";
    if (!$c.util.isEmpty(t3) && !$c.util.isEmpty(t4) && t3 == t4) v = "1";
    if (v == "1") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_032, ["Container Type"]);
        return false;
    }
    return true;
};

scwin.f_invoiceCheck = async function () { // f_commCode→f_commCodeSync, 결과 직접 체크 (AS-IS 동기 패턴 재현)
    scwin.invoiceCheck = "0";

