scwin.f_sellingAmtFcrc = function (row) {
    if (ds_selling.getCellData(row, "crcCd") == "KRW") {
        ds_selling.setCellData(row, "sellAmtFcrc", "0");
    }
    else {
        ds_selling.setCellData(row, "sellAmtFcrc", Math.round((ds_selling.getCellData(row, "chgWt") * ds_selling.getCellData(row, "sellUpr")) * 100) / 100);
    }
};

scwin.f_buyingAmtFcrc = function (row) {
    if (ds_buying.getCellData(row, "crcCd") == "KRW") {
        ds_buying.setCellData(row, "pchsAmtFcrc", "0");
    }
    else {
        ds_buying.setCellData(row, "pchsAmtFcrc", Math.round(($c.num.parseFloat(ds_buying.getCellData(row, "chgWt"), 0) * $c.num.parseFloat(ds_buying.getCellData(row, "pchsUpr"), 0)) * 100) / 100);
    }
};

scwin.f_Currency_Unit = function (curr) {
    let check_Unit = 1;
    if (curr == "JPY" || curr == "ITL" || curr == "IDR" || curr == "ESP") {
        check_Unit = 100;
    }
    return check_Unit;
};

scwin.f_sellingAmt = function (row) {
    if (ds_selling.getCellData(row, "crcCd") == "KRW") {
        ds_selling.setCellData(row, "sellAmt", Math.round($c.num.parseFloat(ds_selling.getCellData(row, "chgWt"), 0) * $c.num.parseFloat(ds_selling.getCellData(row, "sellUpr"), 0)));
    } else {
        let nUnit = scwin.f_Currency_Unit(ds_selling.getCellData(row, "crcCd"));
        ds_selling.setCellData(row, "sellAmt", Math.round($c.num.parseFloat(ds_selling.getCellData(row, "sellAmtFcrc"), 0) * $c.num.parseFloat(ds_selling.getCellData(row, "exRate"), 0)) / nUnit);
    }
};

scwin.f_buyingAmt = function (row) {
    if (ds_buying.getCellData(row, "crcCd") == "KRW") {
        ds_buying.setCellData(row, "pchsAmt", Math.round($c.num.parseFloat(ds_buying.getCellData(row, "chgWt"), 0) * $c.num.parseFloat(ds_buying.getCellData(row, "pchsUpr"), 0)));
    } else {
        let nUnit = scwin.f_Currency_Unit(ds_buying.getCellData(row, "crcCd"));
        ds_buying.setCellData(row, "pchsAmt", Math.round($c.num.parseFloat(ds_buying.getCellData(row, "pchsAmtFcrc"), 0) * $c.num.parseFloat(ds_buying.getCellData(row, "exRate"), 0)) / nUnit);
    }
};

scwin.f_sellingUsdAmt = function (row) {
