scwin.f_PopUp = function (disGubun, chgGubun) {
    switch (disGubun) {
        case "Shipper":
            udc_hhagentattn.setSelectId("retrieveEngClntInfo"); // XML상의 SELECT ID
            udc_hhagentattn.ilCommonPopUp(function (ret) {

                $c.gus.cfSetReturnValue(ret, ed_hhscd, txt_hhs1, [txt_hhs2, txt_hhs3, txt_hhs4, txt_hhs5]);
                ed_hhscd.focus();
            },
                ed_hhscd.getValue().trim(),            // 화면에서의 ??? Code Element의	Value
                txt_hhs1.getValue(),                // 화면에서의 ??? Name Element의	Value
                chgGubun,                       // 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                '10',                            // 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                'Shipper Code,Shipper Name,Address1,Address2,Address3,Address4,Tel,,,CRN',  // Title순서
                '140,300,100,100,100,100,100,,,100',                      // 보여주는 각 컬럼들의 폭
                '8,9',                          // 컬럼중에서 숨기는	컬럼 지정
                null,                           // SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                '500',                          // POP-UP뛰을때 원도우의	사용자 정의	폭
                '500',                          // POP-UP뛰을때 우도우의	사용자 정의	높이
                null,                           // 윈도우 위치 Y좌표
                null,                           // 윈도우 위치 X좌표
                null,                           // 중복체크여부	("F")
                "F",                            // 전체검색허용여부	("F")
                'Shipper search,Shipper Code,Shipper Name');
            break;
        case "Consignee":
            udc_hhagentattn.setSelectId("retrieveEngClntInfo");
            udc_hhagentattn.ilCommonPopUp(function (ret) {
                $c.gus.cfSetReturnValue(ret, ed_hhccd, txt_hhc1, [txt_hhc2, txt_hhc3, txt_hhc4, txt_hhc5]);
            },
                ed_hhccd.getValue().trim(),
                txt_hhc1.getValue(),
                chgGubun,
