            { kcomcd: scwin.hd_kcomcd, seaair: "S", iogb: scwin.hd_hhio, blno: cnd_ed_hhblno.getValue(), mblno: "", mhno: cnd_lc_mhno.getValue() });
    }
    else if (name == "paymentINV") {
        $c.win.openMenu("Payment Invoice", "/ui/il/acc/acpay/ac_106_01_01b.xml", "ac_106_01_01b.xml",
            { kcomcd: scwin.hd_kcomcd, seaair: "S", iogb: scwin.hd_hhio, blno: cnd_ed_hhblno.getValue(), mblno: "", mhno: cnd_lc_mhno.getValue() });
    }
    else if (name == "Invoice") {
        $c.win.openMenu("Invoice", "/ui/il/acc/acinv/ac_101_01_01b.xml", "ac_101_01_01b.xml",
            { kcomcd: scwin.hd_kcomcd, seaair: "S", iogb: scwin.hd_hhio, blno: cnd_ed_hhblno.getValue(), mblno: "", mhno: cnd_lc_mhno.getValue() });
    }
};

