//-------------------------------------------------------------------------
// Get Freight 팝업 오픈
//-------------------------------------------------------------------------

scwin.f_openApi = async function () {

    var linecode = "";

    dma_line_condition.set("hhliner", ed_hhliner.getValue());

    await $c.sbm.execute(sbm_retrieve_linecode);

    linecode = ds_linecode.getCellData(0, "cdNm");

    // ActiveX 실행은 WebSquare/브라우저 환경에서 대부분 차단됨.
    // 대안: 서버 호출/다운로드/외부프로그램 연동 URL 오픈 등으로 교체 권장
    try {
        var objWSH = new ActiveXObject("WScript.Shell");
        var retval = objWSH.Run("C:\dbexp_scrap1\\upgrade.exe job=invsearch&linecode="
            + linecode + "&no=" + cnd_ed_hhmblno.getValue()
            + "&bound=O&callerDT&hblno=" + cnd_ed_hhblno.getValue()
            + "&docuno=" + cnd_lc_mhno.getValue(), 1, true);
    } catch (e) {
        await $c.gus.cfAlertMsg("Tracking 실행이 브라우저 보안 정책으로 차단될 수 있습니다.\n관리자/서버 연동 방식으로 변경이 필요합니다.");
        return false;
    }
}

scwin.btn_Tracking_onclick = function (e) {
    scwin.f_Tracking();
};

//---------------------------------------------------------
// 선사 트래킹
//---------------------------------------------------------
scwin.f_Tracking = async function () {
    if (ds_houseblList.getRowCount() === 0) {
        await $c.win.alert("선사 Tracking 할 Direct B/L을 조회해 주세요.");
        return;
    }

    const r = ds_houseblList.getRowPosition();
    const vlinerCd = ds_houseblList.getCellData(r, "hhliner");
    const vparm = ds_houseblList.getCellData(r, "hhmblno");

    // liner명 조회(예: 공통코드 트랜잭션으로 ds_liner 채움)
    ds_liner.removeAll();

    dma_code.setJSON({ grpCd: "IL052", cd: vlinerCd });
    // await $c.sbm.execute(sbm_code); // onsubmitdone에서 ds_liner.setJSON 처리
    await $c.sbm.execute(sbm_code).then(function (e) {
        ds_liner.setJSON(e.responseJSON.GAUCE);
        let vline = "";
        if (ds_liner.getRowCount() > 0 && !$c.util.isEmpty(ds_liner.getCellData(0, "cdNm"))) {
            vline = ds_liner.getCellData(0, "cdNm");
        }

        // ActiveX 실행은 WebSquare/브라우저 환경에서 대부분 차단됨.
        // 대안: 서버 호출/다운로드/외부프로그램 연동 URL 오픈 등으로 교체 권장
        try {
            var objWSH = new ActiveXObject("WScript.Shell");
            var retval = objWSH.Run("C:\dbexp_scrap1\\upgrade.exe job=" + "blsearch" + "&linecode=" + vline + "&no=" + vparm + "&", 1, true);
        } catch (e) {
            $c.gus.cfAlertMsg("Tracking 실행이 브라우저 보안 정책으로 차단될 수 있습니다.\n관리자/서버 연동 방식으로 변경이 필요합니다.");
            return false;
        }
    });
};

