    var strClntNo = "";
    if (gubun == "1") {
        strClntNo = cnd_ed_hhblno.getValue();
        if (!$c.util.isEmpty(strClntNo)) {
            scwin._comboTarget = "HMHNO1";
            await scwin.f_commCode("ilCommonEBC", "retriveSeaHouseMhnoListCombo", strClntNo);
        } else {
