scwin.f_runExcel = async function () {
    var totCnt = ds_selling.getRowCount();
    var sheetTitle = "Selling List";

    if (totCnt != 0) {
        let cfrm = await $c.win.confirm("EXCEL로 다운로드 받으시겠습니까?");

        if (cfrm) {

            const options = {
                fileName: sheetTitle,
                sheetName: sheetTitle
            };

            $c.data.downloadGridViewExcel(gr_selling, options);
        }
    } else {
        $c.gus.cfAlertMsg(MSG_CM_WRN_002);
    }
};

